	<!-- Section: How ClearSky Enters New Markets -->
	<div
		class="flex flex-col items-center px-[6px] text-center lg:pt-[48px] lg:pb-[40px]"
	>
		<h2 class="mb-[20px] text-[24px] leading-[24px] font-semibold text-[#4267AD]">
			Entering New Markets
		</h2>
		<p class="mb-[20px] text-[11px] leading-[1.3] font-semibold text-[#1F2A44]">
			Each sector is sized by market capacity —  ensuring <br class="block lg:hidden" /> 
			limited access, real opportunity, and over saturation.
		</p>
		<!-- Tabs -->
		<div class="-mx-[6px] mb-[20px] flex w-[calc(100%+12px)] items-end justify-evenly pb-1">
			{#each tabSpecs as tab (tab.id)}
				<div class="relative flex flex-col items-center">
					<button
						onclick={() => {
							activeSector = tab.id;
						}}
						class="flex flex-col items-center transition-all"
					>
						<div class="flex h-[44px] w-[51px] items-end justify-center">
							{#if tab.id === 'Trades'}
								{@render ContractorsSVG()}
							{:else if tab.id === 'Tourism'}
								{@render TourismSVG()}
							{:else if tab.id === 'Prof-Services'}
								{@render ProfessionalSVG()}
							{:else if tab.id === 'Manufacturing'}
								{@render ManufacturersSVG()}
							{/if}
						</div>
						{#if activeSector === tab.id}
							<div class="absolute -bottom-px h-[2px] w-[61px] bg-[#1F2A44]"></div>
						{/if}
					</button>
				</div>
			{/each}
		</div>

		<!-- Sector Card -->
		<div
			class="w-full overflow-hidden rounded-[12px] border border-[#E5E7EB] bg-white text-left shadow-[1px_3px_5px_3px_rgba(0,0,0,0.1)] transition-all duration-300"
		>
			<div class="px-[12px] pt-[15px] lg:pt-px pb-[15px] lg:block flex flex-col lg:font-normal font-semibold gap-[8px]">
				<p class=" text-[14px] font-medium text-text-dark lg:text-left text-center">
					{sectorData[activeSector].title}
				</p>
				<p class="text-[11px] lg:text-[14px] leading-[1.5] text-text-dark lg:text-left text-center whitespace-pre-line lg:whitespace-normal">
					{sectorData[activeSector].description}
				</p>
				<div class="flex items-center gap-2 lg:justify-start justify-center">
					<span class="text-[12px] lg:text-[14px] text-text-dark">{sectorData[activeSector].categories} →</span>
					<button
						onclick={() => (isExpanded = !isExpanded)}
						class="text-[12px] lg:text-[14px] font-medium text-[#4267AD]"
					>
						{isExpanded ? 'Collapse' : 'Expand'}
					</button>
				</div>
			</div>

			<!-- Expanded Content -->
			{#if isExpanded}
				<div class="border-t border-[#8F8B8B] px-[24px] py-[24px]">
					<h5 class="mb-4 text-[13px] font-bold text-text-dark">
						{sectorData[activeSector].expanded.howItWorks}
					</h5>

					<div class="space-y-6">
						{#each sectorData[activeSector].expanded.points as point (point.title)}
							<div class="space-y-1">
								<p class="text-[12px] font-bold text-black">{point.title}</p>
								<p class="text-[12px] leading-[15px] font-medium text-black">
									{point.subtitle}
								</p>

								{#if point.list}
									<ul class="mt-2 ml-4 list-disc space-y-1">
										{#each point.list as item (item)}
											<li class="pl-1 text-[12px] font-medium text-black">{item}</li>
										{/each}
									</ul>
								{/if}

								{#if point.footer}
									<p class="mt-2 text-[12px] font-medium text-black">
										{point.footer}
									</p>
								{/if}
							</div>
						{/each}
					</div>
				</div>
			{/if}
		</div>
	</div>

